import itertools, math
from sympy import symbols, Poly, Matrix, ZZ, groebner, resultant
x,y = symbols('x y')
N = 
f = Poly(x*y*(x**2+x+1), x, y, domain=ZZ)

def monomial_key(mon):
    return mon

def small_roots(bounds, m=1, d=4):
    polys=[]
    for i in range(m+1):
        base = Poly((N**(m-i))*(f.as_expr()**i), x, y, domain=ZZ)
        for sx,sy in itertools.product(range(d), repeat=2):
            g = Poly(base.as_expr() * x**sx * y**sy, x, y, domain=ZZ)
            polys.append(g)
    monomials = sorted({mon for g in polys for mon in g.monoms()})
    M=[]
    scales=[]
    for mon in monomials:
        a,b=mon
        scales.append((bounds[0]**a)*(bounds[1]**b))
    for g in polys:
        coeffs = g.as_dict()
        M.append([coeffs.get(mon,0)*scales[j] for j,mon in enumerate(monomials)])
    M = Matrix(M)
    print('matrix', M.rows, M.cols)
    B = M.lll()
    H=[]
    for row in B.tolist():
        expr=0
        for coeff,scale,mon in zip(row,scales,monomials):
            if coeff:
                a,b=mon
                c = coeff//scale if coeff % scale == 0 else coeff/scale
                expr += c*(x**a)*(y**b)
        # clear denominators if any
        P = Poly(expr, x, y).clear_denoms()[1]
        if P.as_expr()!=0:
            H.append(P)
    print('nonzero H', len(H))
    for i in range(min(len(H),8)):
        for j in range(i+1,min(len(H),8)):
            try:
                R = resultant(H[i].as_expr(), H[j].as_expr(), y)
                if R==0:
                    continue
                RP = Poly(R, x, domain=ZZ)
                print('resultant degree', i,j, RP.degree())
                fac = RP.factor_list()
                for poly, mult in fac[1]:
                    deg = poly.degree()
                    if deg<=6:
                        roots = poly.nroots(n=deg, maxsteps=50)
                        for rr in roots:
                            if abs(complex(rr).imag) < 1e-8:
                                xv = int(round(float(complex(rr).real)))
                                if 0 < xv < bounds[0]:
                                    val = xv*(xv*xv+xv+1)
                                    if N % val == 0:
                                        print('FOUND x', xv.bit_length(), xv)
                                        print('r bits', (N//val).bit_length())
                                        return xv, N//val
            except Exception as e:
                pass
    return None

for b in [192,224,256,288,320,384,448,512,576,640]:
    X=2**b
    Y=2**(3072-3*b)
    print('trying', b, 'Ybits', 3072-3*b)
    try:
        res = small_roots((X,Y), m=1, d=3)
        print('res',res)
        if res:
            break
    except Exception as e:
        print('err', e)
